import React, { useState } from "react";
import "../../styles/auth.css";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

function Register() {
  const navigate = useNavigate();
  const { register } = useAuth();

  const [form, setForm] = useState({
    firstName: "", lastName: "", email: "",
    password: "", confirmPassword: "",
    phone: "", gender: "", dob: "", role: "freelancer",
  });
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleRegister = async (e) => {
    e.preventDefault();
    setMessage("");
    if (form.password !== form.confirmPassword) { setMessage("❌ Passwords do not match!"); return; }
    if (form.phone.length !== 10) { setMessage("❌ Enter valid 10-digit phone number!"); return; }
    setLoading(true);
    const result = await register({
      name: `${form.firstName} ${form.lastName}`.trim(),
      email: form.email, password: form.password,
      phone: form.phone, gender: form.gender, dob: form.dob, role: form.role,
    });
    setLoading(false);
    if (result.success) {
      setMessage("✅ Registered! Redirecting...");
      setTimeout(() => navigate("/login"), 1500);
    } else {
      setMessage(result.message);
    }
  };

  const inp = {
    width: "100%", padding: "7px 10px", fontSize: "12px",
    borderRadius: "7px", border: "1.5px solid #e5e7eb",
    outline: "none", background: "#f9fafb", boxSizing: "border-box"
  };
  const lbl = { fontSize: "11px", fontWeight: "600", color: "#374151", marginBottom: "3px", display: "block" };

  return (
    <div className="register-page">

      {/* LEFT PANEL */}
      <div className="auth-left-panel">
        <h1 style={{ fontSize: "28px" }}>Join<br /><span>FreelanceHub</span></h1>
        <p style={{ fontSize: "13px" }}>Connect with top talent or find exciting projects today.</p>
        <div className="auth-features" style={{ marginTop: "24px", gap: "12px" }}>
          {[
            ["💻", "Freelancers — showcase skills & get hired"],
            ["🏢", "Clients — post projects & find experts"],
            ["💬", "Chat directly with your team"],
            ["📊", "Track earnings and project progress"],
          ].map(([icon, text], i) => (
            <div key={i} className="auth-feature-item" style={{ fontSize: "13px" }}>
              <div className="feature-icon" style={{ width: "30px", height: "30px", fontSize: "14px" }}>{icon}</div>
              <span>{text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* RIGHT PANEL */}
      <div className="auth-right-panel" style={{ padding: "20px", overflowY: "auto" }}>
        <div className="register-wrapper" style={{ maxWidth: "420px", padding: "20px 24px" }}>

          {/* HEADER */}
          <div className="register-header" style={{ marginBottom: "12px" }}>
            <div className="logo-icon" style={{ fontSize: "20px" }}>🧳</div>
            <h2 style={{ fontSize: "18px", marginBottom: "2px" }}>Create Account</h2>
            <p style={{ fontSize: "11px" }}>Join FreelanceHub today</p>
          </div>

          {/* TOGGLE */}
          <div className="toggle-container" style={{ marginBottom: "12px" }}>
            <button onClick={() => navigate("/login")}>Login</button>
            <button className="active">Register</button>
          </div>

          {message && (
            <p className="success-msg" style={{ padding: "6px", fontSize: "11px", marginBottom: "8px" }}>
              {message}
            </p>
          )}

          <form onSubmit={handleRegister} className="register-form" style={{ gap: "0" }}>

            {/* Row: First + Last Name */}
            <div style={{ display: "flex", gap: "8px", marginBottom: "8px" }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>First Name</label>
                <input style={inp} type="text" name="firstName" placeholder="John"
                  value={form.firstName} onChange={handleChange} required />
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Last Name</label>
                <input style={inp} type="text" name="lastName" placeholder="Doe"
                  value={form.lastName} onChange={handleChange} required />
              </div>
            </div>

            {/* Email */}
            <div style={{ marginBottom: "8px" }}>
              <label style={lbl}>Email ID</label>
              <input style={inp} type="email" name="email" placeholder="john@example.com"
                value={form.email} onChange={handleChange} required />
            </div>

            {/* Row: Password + Confirm */}
            <div style={{ display: "flex", gap: "8px", marginBottom: "8px" }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Password</label>
                <input style={inp} type="password" name="password" placeholder="••••••••"
                  value={form.password} onChange={handleChange} required />
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Confirm Password</label>
                <input style={inp} type="password" name="confirmPassword" placeholder="••••••••"
                  value={form.confirmPassword} onChange={handleChange} required />
              </div>
            </div>

            {/* Phone */}
            <div style={{ marginBottom: "8px" }}>
              <label style={lbl}>Phone Number</label>
              <input style={inp} type="tel" name="phone" placeholder="9876543210"
                maxLength="10" value={form.phone} onChange={handleChange} required />
            </div>

            {/* Row: Gender + DOB */}
            <div style={{ display: "flex", gap: "8px", marginBottom: "8px" }}>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Gender</label>
                <select name="gender" value={form.gender} onChange={handleChange} required
                  style={{ ...inp }}>
                  <option value="">Select</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                </select>
              </div>
              <div style={{ flex: 1 }}>
                <label style={lbl}>Date of Birth</label>
                <input style={inp} type="date" name="dob"
                  value={form.dob} onChange={handleChange} required />
              </div>
            </div>

            {/* Register As */}
            <div style={{ marginBottom: "10px" }}>
              <label style={lbl}>Register As</label>
              <div style={{ display: "flex", gap: "8px" }}>
                {[["freelancer", "👤", "Freelancer"], ["client", "👥", "Client"]].map(([val, icon, label]) => (
                  <div key={val}
                    onClick={() => setForm({ ...form, role: val })}
                    style={{
                      flex: 1, textAlign: "center", padding: "8px 6px",
                      borderRadius: "8px", cursor: "pointer", transition: "0.2s",
                      border: form.role === val ? "2px solid #0f766e" : "1.5px solid #e5e7eb",
                      background: form.role === val ? "#f0fdf9" : "#f9fafb",
                    }}>
                    <span style={{ fontSize: "16px" }}>{icon}</span>
                    <p style={{ fontSize: "11px", fontWeight: "600", marginTop: "2px",
                      color: form.role === val ? "#0f766e" : "#6b7280" }}>{label}</p>
                  </div>
                ))}
              </div>
            </div>

            <button type="submit" className="create-btn"
              style={{ marginTop: "4px", padding: "9px", fontSize: "13px" }}
              disabled={loading}>
              {loading ? "Creating..." : "Create Account"}
            </button>

          </form>
        </div>
      </div>

    </div>
  );
}

export default Register;
